CREATE OR REPLACE FUNCTION purchase_order_fts_match(search_vector tsvector, query text)
RETURNS boolean AS $$
    SELECT search_vector @@ plainto_tsquery('english', query);
$$ LANGUAGE sql IMMUTABLE;

CREATE OR REPLACE FUNCTION purchase_order_fts_rank(search_vector tsvector, query text)
RETURNS real AS $$
    SELECT ts_rank(search_vector, plainto_tsquery('english', query));
$$ LANGUAGE sql IMMUTABLE;
